<?php $status=(int)($data['status']??500); $messages=[400=>['A card landed sideways.','That request could not be understood. Check the details and try again.'],401=>['This room needs a sign-in.','Please log in to continue. Your destination will be preserved when it is safe to do so.'],403=>['That door is reserved.','Your account does not have permission to enter this area.'],404=>['This chair is empty.','The page may have moved, or the address may be mistyped.'],419=>['Your session went cool.','For your protection, the form token expired. Refresh the page and try once more.'],429=>['Let’s take a breath.','Too many requests arrived in a short time. Wait a little before trying again.'],500=>['The table needs a moment.','Something unexpected happened. No stack trace, credentials, or technical details are shown publicly.']]; [$heading,$message]=$messages[$status]??$messages[500]; $heading=(string)($data['heading']??$heading); $message=(string)($data['message']??$message); ?>
<section class="error-page shell"><div class="error-card"><p class="error-code" aria-label="Error <?= $esc((string)$status) ?>"><?= $esc((string)$status) ?></p><p class="eyebrow">Purple Parlor notice</p><h1 class="heading-error"><?= $esc($heading) ?></h1><p class="lede"><?= $esc($message) ?></p><div class="button-row"><?php if($status===401): ?><a class="button button-gold" href="<?= $url('auth.login', [], '/login') ?>">Log in</a><?php elseif($status===429&&!empty($data['retry_after'])): ?><span class="tag tag-gold">Try again in <?= $esc((string)$data['retry_after']) ?> seconds</span><?php else: ?><a class="button button-gold" href="<?= $url('home', [], '/') ?>">Return home</a><?php endif; ?><a class="button button-ghost" href="<?= $url('help.index', [], '/help') ?>">Visit help</a></div><p class="fine-print">Request reference: <code><?= $esc((string)($data['request_id']??'not available')) ?></code></p></div></section>
